import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import "./FreelancerDashboard.css";

function FreelancerDashboard() {
  const [user, setUser] = useState(null);
  const [proposals, setProposals] = useState([]);
  const [stats, setStats] = useState({
    totalBids: 0,
    activeBids: 0
  });
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("access");
    if (!token) {
      navigate("/");
    } else {
      fetchDashboardData();
    }
  }, [navigate]);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('access');
      
      // Get current user info
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      // Get profile for full name
      const profileRes = await axios.get('http://127.0.0.1:8000/api/users/profile/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      const displayName = profileRes.data.full_name || userRes.data.first_name || userRes.data.username;
      setUser({ ...userRes.data, displayName });
      
      // Fetch freelancer's proposals
      const proposalsRes = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      setProposals(proposalsRes.data.slice(0, 3)); // Show only 3 latest
      
      setStats({
        totalBids: proposalsRes.data.length,
        activeBids: proposalsRes.data.filter(p => p.status === 'pending').length
      });
      
      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'pending': return '#ffc107';
      case 'accepted': return '#28a745';
      case 'rejected': return '#dc3545';
      default: return '#6c757d';
    }
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="dashboard-container">
      {/* Top Bar - Updated with Edit Profile button */}
      <div className="top-bar">
        <div className="logo">🔷 TalentLink</div>
        <div className="user-menu">
          <span className="username">👤 {user?.displayName || 'Freelancer'}</span>
          <button 
            onClick={() => navigate('/profile')} 
            className="profile-btn"
          >
            Edit Profile
          </button>
          <button onClick={handleLogout} className="logout-btn">Logout</button>
        </div>
      </div>

      {/* Welcome Section */}
      <div className="welcome-section">
        <h2>👋 Welcome back, {user?.displayName || 'Freelancer'}!</h2>
        <span className="date">{new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <span className="stat-label">📊 Total Bids</span>
          <span className="stat-value">{stats.totalBids}</span>
        </div>
        <div className="stat-card">
          <span className="stat-label">⚡ Active Bids</span>
          <span className="stat-value">{stats.activeBids}</span>
        </div>
      </div>

      {/* Browse Projects Button */}
      <button className="browse-btn" onClick={() => navigate('/projects')}>
        🔍 BROWSE PROJECTS
      </button>

      {/* My Proposals Section */}
      <div className="section-header">
        <h3>📋 MY PROPOSALS</h3>
        <button className="view-all" onClick={() => navigate('/proposals')}>View All →</button>
      </div>
      
      {proposals.length > 0 ? (
        <div className="proposals-list">
          {proposals.map(proposal => (
            <div key={proposal.id} className="proposal-card">
              <div className="proposal-info">
                <h4>{proposal.project_title}</h4>
                <div className="proposal-details">
                  <span>💰 Bid: ₹{proposal.bid_amount}</span>
                  <span>⏱️ {proposal.estimated_days} days</span>
                  <span className="status-badge" style={{ backgroundColor: getStatusColor(proposal.status) }}>
                    {proposal.status}
                  </span>
                </div>
              </div>
              <div className="proposal-actions">
                <button 
                  className="view-btn"
                  onClick={() => navigate(`/projects/${proposal.project}`)}
                >
                  View Project
                </button>
                {proposal.status === 'accepted' && (
                  <button 
                    className="message-btn"
                    onClick={() => navigate('/messages')}
                  >
                    💬 Message
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="empty-state">
          <p>No proposals yet. Browse projects and submit your first bid!</p>
          <button className="browse-small-btn" onClick={() => navigate('/projects')}>
            Browse Projects
          </button>
        </div>
      )}
    </div>
  );
}

export default FreelancerDashboard;
